#include <bits/stdc++.h>
using namespace std;
bool has_cycle_util(int v, vector<vector<int>>& graph, vector<bool>& visited, vector<bool>& recursion_stack) {
    visited[v] = true;
    recursion_stack[v] = true;
    for (int neighbor : graph[v]) {
        if (!visited[neighbor]) {
            if (has_cycle_util(neighbor, graph, visited, recursion_stack)) {
                return true;
            }
        } else if (recursion_stack[neighbor]) {
            return true;
        }
    }
    recursion_stack[v] = false;
    return false;
}
bool has_cycle(vector<vector<int>>& graph) {
    vector<bool> visited(graph.size(), false);
    vector<bool> recursion_stack(graph.size(), false);
    for (int i = 0; i < graph.size(); i++) {
        if (!visited[i]) {
            if (has_cycle_util(i, graph, visited, recursion_stack)) {
                return true;
            }
        }
    }
    return false;
}
